export type ImageSize = '1K' | '2K' | '4K';

export interface Scene {
  id: string;
  title: string;
  description: string;
  visualPrompt: string;
  imageUrl?: string;
  status: 'pending' | 'generating' | 'completed' | 'error';
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

export interface ScriptAnalysis {
  scenes: Scene[];
}

declare global {
  interface Window {
    aistudio: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
  }
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { Scene, ImageSize, ScriptAnalysis } from "../types";

export class GeminiService {
  private static getAI() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  static async analyzeScript(scriptText: string): Promise<ScriptAnalysis> {
    const ai = this.getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `Analyze the following script and break it down into a sequence of key visual scenes for a storyboard. 
      For each scene, provide a descriptive title, a summary of what's happening, and a detailed visual prompt for an image generation model.

      Script:
      ${scriptText}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            scenes: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  visualPrompt: { type: Type.STRING }
                },
                required: ["id", "title", "description", "visualPrompt"]
              }
            }
          },
          required: ["scenes"]
        }
      }
    });

    const text = response.text || "";
    return JSON.parse(text) as ScriptAnalysis;
  }

  static async generateStoryboardImage(prompt: string, size: ImageSize): Promise<string> {
    const ai = this.getAI();
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-image-preview',
        contents: {
          parts: [{ text: `Cinematic storyboard art style: ${prompt}` }]
        },
        config: {
          imageConfig: {
            aspectRatio: "16:9",
            imageSize: size
          }
        }
      });

      const parts = response.candidates?.[0]?.content?.parts || [];
      for (const part of parts) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
      throw new Error("No image data returned from model");
    } catch (error: any) {
      if (error.message?.includes("Requested entity was not found")) {
        throw new Error("KEY_RESET_REQUIRED");
      }
      throw error;
    }
  }

  static async chat(message: string, history: { role: 'user' | 'model', text: string }[]): Promise<string> {
    const ai = this.getAI();
    const chat = ai.chats.create({
      model: 'gemini-3-pro-preview',
      config: {
        systemInstruction: "You are a professional storyboard artist and creative consultant. Assist the user with their scriptwriting and visual storytelling questions."
      }
    });

    // Simple implementation of sending one message at a time to keep it clean
    const response = await chat.sendMessage({ message });
    return response.text || "I'm sorry, I couldn't process that.";
  }
}

