import React, { useState, useRef, useEffect } from 'react';
import { GeminiService } from '../services/geminiService';
import { ChatMessage } from '../types';

const ChatBot: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: "Hi! I'm your creative assistant. Need help with your script or storyboard?", timestamp: Date.now() }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = { role: 'user', text: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const response = await GeminiService.chat(input, messages.map(m => ({ role: m.role, text: m.text })));
      setMessages(prev => [...prev, { role: 'model', text: response, timestamp: Date.now() }]);
    } catch (err) {
      setMessages(prev => [...prev, { role: 'model', text: "Error connecting to AI.", timestamp: Date.now() }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className={`fixed bottom-6 right-6 z-[100] transition-all duration-300 ${isOpen ? 'w-[380px] h-[550px]' : 'w-14 h-14'}`}>
      {isOpen ? (
        <div className="w-full h-full bg-zinc-900 border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden">
          <div className="p-4 border-b border-white/10 bg-zinc-800 flex justify-between items-center">
            <h3 className="font-semibold text-white">Creative Assistant</h3>
            <button onClick={() => setIsOpen(false)} className="p-1 hover:bg-white/10 rounded-md">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
              </svg>
            </button>
          </div>

          <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] px-4 py-2 rounded-2xl text-sm ${m.role === 'user' ? 'bg-purple-600 text-white' : 'bg-white/5 text-zinc-300 border border-white/10'}`}>
                  {m.text}
                </div>
              </div>
            ))}
            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white/5 px-4 py-2 rounded-2xl text-sm border border-white/10 animate-pulse text-zinc-400">
                  Thinking...
                </div>
              </div>
            )}
          </div>

          <div className="p-4 bg-zinc-800 border-t border-white/10 flex gap-2">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Ask anything..."
              className="flex-1 bg-white/5 border border-white/10 rounded-full px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-purple-500"
            />
            <button onClick={handleSend} className="bg-purple-600 p-2 rounded-full hover:bg-purple-500 transition-colors">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" />
              </svg>
            </button>
          </div>
        </div>
      ) : (
        <button
          onClick={() => setIsOpen(true)}
          className="w-full h-full bg-purple-600 rounded-full flex items-center justify-center shadow-lg shadow-purple-500/30 hover:bg-purple-500 transition-all hover:scale-110"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
          </svg>
        </button>
      )}
    </div>
  );
};

export default ChatBot;

import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import ChatBot from './components/ChatBot';
import { GeminiService } from './services/geminiService';
import { Scene, ImageSize } from './types';

const App: React.FC = () => {
  const [scriptText, setScriptText] = useState('');
  const [scenes, setScenes] = useState<Scene[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedSize, setSelectedSize] = useState<ImageSize>('1K');
  const [hasApiKey, setHasApiKey] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    checkApiKey();
  }, []);

  const checkApiKey = async () => {
    const has = await window.aistudio.hasSelectedApiKey();
    setHasApiKey(has);
  };

  const handleSelectKey = async () => {
    await window.aistudio.openSelectKey();
    setHasApiKey(true);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        setScriptText(ev.target?.result as string);
      };
      reader.readAsText(file);
    }
  };

  const analyzeScript = async () => {
    if (!scriptText.trim()) return;
    setIsAnalyzing(true);
    setError(null);
    try {
      const analysis = await GeminiService.analyzeScript(scriptText);
      setScenes(analysis.scenes.map(s => ({ ...s, status: 'pending' })));
    } catch (err) {
      setError("Failed to analyze script. Please try again.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const generateAllImages = async () => {
    if (!hasApiKey) {
      await handleSelectKey();
    }

    setIsGenerating(true);
    const updatedScenes = [...scenes];

    for (let i = 0; i < updatedScenes.length; i++) {
      try {
        setScenes(prev => {
          const s = [...prev];
          s[i].status = 'generating';
          return s;
        });

        const imageUrl = await GeminiService.generateStoryboardImage(updatedScenes[i].visualPrompt, selectedSize);

        setScenes(prev => {
          const s = [...prev];
          s[i].status = 'completed';
          s[i].imageUrl = imageUrl;
          return s;
        });
      } catch (err: any) {
        if (err.message === "KEY_RESET_REQUIRED") {
          setHasApiKey(false);
          setError("API Key verification failed. Please select your key again.");
          break;
        }
        setScenes(prev => {
          const s = [...prev];
          s[i].status = 'error';
          return s;
        });
      }
    }
    setIsGenerating(false);
  };

  return (
    <div className="min-h-screen bg-[#0a0a0a] text-zinc-200">
      <Header />

      <main className="max-w-7xl mx-auto px-6 py-12 pb-32">
        <div className="mb-12 text-center">
          <h2 className="text-5xl md:text-6xl font-serif mb-4 text-white">Bring your script to life.</h2>
          <p className="text-zinc-400 text-lg max-w-2xl mx-auto">
            Upload your screenplay or treatment. We'll decompose it into scenes and generate cinematic storyboard frames automatically.
          </p>
        </div>

        {/* Action Controls */}
        <div className="bg-zinc-900/50 border border-white/10 rounded-3xl p-8 mb-12 shadow-xl">
          <div className="grid md:grid-cols-2 gap-8">
            <div className="space-y-4">
              <label className="block text-sm font-medium text-zinc-300">Your Script</label>
              <textarea
                value={scriptText}
                onChange={(e) => setScriptText(e.target.value)}
                placeholder="Paste your script here or upload a file..."
                className="w-full h-64 bg-black/40 border border-white/10 rounded-2xl p-4 text-sm focus:outline-none focus:ring-2 focus:ring-purple-500 transition-all font-mono resize-none"
              />
              <div className="flex gap-4">
                <div className="relative flex-1">
                  <input
                    type="file"
                    accept=".txt,.doc,.docx,.pdf"
                    onChange={handleFileUpload}
                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                  />
                  <button className="w-full flex items-center justify-center gap-2 bg-white/5 border border-white/10 text-white rounded-xl py-3 hover:bg-white/10 transition-colors">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                      <path fillRule="evenodd" d="M3 17a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1zM6.293 6.707a1 1 0 010-1.414l3-3a1 1 0 011.414 0l3 3a1 1 0 01-1.414 1.414L11 5.414V13a1 1 0 11-2 0V5.414L7.707 6.707a1 1 0 01-1.414 0z" clipRule="evenodd" />
                    </svg>
                    Upload File
                  </button>
                </div>
                <button
                  onClick={analyzeScript}
                  disabled={isAnalyzing || !scriptText.trim()}
                  className="flex-1 bg-purple-600 hover:bg-purple-500 disabled:bg-zinc-800 disabled:text-zinc-500 text-white rounded-xl py-3 font-semibold transition-all flex items-center justify-center gap-2"
                >
                  {isAnalyzing ? (
                    <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                  ) : "Analyze Script"}
                </button>
              </div>
            </div>

            <div className="space-y-6 flex flex-col justify-between">
              <div>
                <label className="block text-sm font-medium text-zinc-300 mb-4">Output Quality</label>
                <div className="grid grid-cols-3 gap-3">
                  {(['1K', '2K', '4K'] as ImageSize[]).map((size) => (
                    <button
                      key={size}
                      onClick={() => setSelectedSize(size)}
                      className={`py-4 rounded-2xl border transition-all ${selectedSize === size ? 'bg-purple-600/20 border-purple-500 text-purple-300' : 'bg-white/5 border-white/10 text-zinc-500 hover:bg-white/10'}`}
                    >
                      <div className="font-bold">{size}</div>
                      <div className="text-[10px] uppercase opacity-60">Resolution</div>
                    </button>
                  ))}
                </div>
                <p className="mt-4 text-xs text-zinc-500 leading-relaxed italic">
                  Note: Higher resolutions take longer to generate and may require a paid API key for Gemini 3 Pro Image.
                </p>
              </div>

              {!hasApiKey && (
                <div className="bg-amber-500/10 border border-amber-500/20 rounded-2xl p-4">
                  <p className="text-xs text-amber-200/80 mb-3">
                    A paid API key is required for high-quality image generation with Gemini 3 Pro.
                  </p>
                  <button
                    onClick={handleSelectKey}
                    className="w-full bg-amber-600 hover:bg-amber-500 text-white text-sm font-bold py-2 rounded-lg transition-colors"
                  >
                    Select API Key
                  </button>
                </div>
              )}

              <button
                onClick={generateAllImages}
                disabled={isGenerating || scenes.length === 0}
                className="w-full bg-gradient-to-r from-purple-600 to-blue-600 hover:from-purple-500 hover:to-blue-500 disabled:from-zinc-800 disabled:to-zinc-800 disabled:text-zinc-500 text-white rounded-xl py-4 font-bold text-lg shadow-lg shadow-purple-500/10 transition-all flex items-center justify-center gap-3"
              >
                {isGenerating ? (
                  <div className="w-6 h-6 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                ) : (
                  <>
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                    </svg>
                    Generate Storyboard
                  </>
                )}
              </button>
            </div>
          </div>
        </div>

        {error && (
          <div className="mb-8 p-4 bg-red-500/10 border border-red-500/20 rounded-2xl text-red-400 text-center">
            {error}
          </div>
        )}

        {/* Scene Sequence */}
        <div className="space-y-12">
          {scenes.map((scene, idx) => (
            <div key={scene.id} className="group grid md:grid-cols-12 gap-8 items-start animate-fade-in">
              <div className="md:col-span-1 flex flex-col items-center">
                <div className="w-10 h-10 rounded-full bg-zinc-800 flex items-center justify-center font-bold text-purple-400 border border-white/10 group-hover:bg-purple-600 group-hover:text-white transition-all">
                  {idx + 1}
                </div>
                <div className="w-px h-full bg-zinc-800 mt-4 hidden md:block" />
              </div>

              <div className="md:col-span-4 space-y-4">
                <h3 className="text-2xl font-semibold text-white">{scene.title}</h3>
                <p className="text-zinc-400 text-sm leading-relaxed">{scene.description}</p>
                <div className="p-4 bg-white/5 rounded-2xl border border-white/5">
                  <h4 className="text-[10px] uppercase tracking-wider text-zinc-500 font-bold mb-2">AI Visual Prompt</h4>
                  <p className="text-xs text-zinc-400 italic">"{scene.visualPrompt}"</p>
                </div>
              </div>

              <div className="md:col-span-7 aspect-video relative rounded-3xl overflow-hidden bg-zinc-900 border border-white/10 shadow-2xl">
                {scene.imageUrl ? (
                  <img src={scene.imageUrl} alt={scene.title} className="w-full h-full object-cover" />
                ) : (
                  <div className="w-full h-full flex flex-col items-center justify-center text-zinc-600">
                    {scene.status === 'generating' ? (
                      <div className="flex flex-col items-center gap-4">
                        <div className="w-12 h-12 border-2 border-purple-500/30 border-t-purple-500 rounded-full animate-spin" />
                        <span className="text-sm font-medium animate-pulse text-purple-400">Capturing cinematic frame...</span>
                      </div>
                    ) : scene.status === 'error' ? (
                      <div className="flex flex-col items-center gap-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-red-500/50" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                        </svg>
                        <span className="text-xs uppercase tracking-widest text-red-500/50">Generation Failed</span>
                      </div>
                    ) : (
                      <div className="flex flex-col items-center gap-2">
                         <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 opacity-20" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                        </svg>
                        <span className="text-xs uppercase tracking-widest opacity-20">Awaiting Generation</span>
                      </div>
                    )}
                  </div>
                )}
                <div className="absolute top-4 right-4 bg-black/60 backdrop-blur-md px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest border border-white/10">
                  Frame {idx + 1}
                </div>
              </div>
            </div>
          ))}

          {scenes.length === 0 && !isAnalyzing && (
            <div className="py-32 flex flex-col items-center justify-center text-zinc-600 space-y-4">
              <div className="w-24 h-24 rounded-full bg-white/5 flex items-center justify-center">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 opacity-20" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                </svg>
              </div>
              <p className="text-sm tracking-wide uppercase font-medium">No script analyzed yet</p>
            </div>
          )}
        </div>
      </main>

      <ChatBot />

      <footer className="border-t border-white/5 py-12 text-center text-zinc-600 text-sm">
        <p>&copy; {new Date().getFullYear()} Script2Storyboard AI. Built with Google Gemini 3 Pro.</p>
      </footer>

      <style>{`
        @keyframes fade-in {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
        .animate-fade-in {
          animation: fade-in 0.5s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

export default App;

